#include <stdio.h>

int main() {
  int arr[] = {10, 20, 30, 40, 50};
  int *p = arr;
  // Using array notation
  for (int i = 0; i < 5; i++) {
    printf("%d ", arr[i]);
  }
  printf("\n");
  // Using pointer notation
  for (int i = 0; i < 5; i++) {
    printf("%d ", *(p + i));
  }
  printf("\n");
  return 0;
}
